module LFSR (
    output reg [3:0] out,
    input clk,
    input rst
);

reg [3:0] out_next;
wire feedback;

assign feedback = ~(out[3] ^ out[2]);

always @(posedge clk or posedge rst) begin
    if (rst) begin
        out_next <= 4'b0000; 
    end else begin
        out_next <= {out[2:0], feedback}; 
    end
end

assign out = out_next;
endmodule
